export default function bind(fn, thisArg) {
  return function wrap() {
    return fn.apply(thisArg, arguments);
  };
}

export function formatNum(num, precision) {
	if (precision === false) { return num; }
	const pow = 10 ** (precision === undefined ? 6 : precision);
	return Math.round(num * pow) / pow;
}

function baseProperty(key) {
  return function(object) {
    return object == null ? undefined : object[key];
  };
}

function basePropertyOf(object) {
  return function(key) {
    return object == null ? undefined : object[key];
  };
}

function stringToArray(string) {
  return hasUnicode(string)
    ? unicodeToArray(string)
    : asciiToArray(string);
}

function arrayIncludes(array, value) {
  var length = array == null ? 0 : array.length;
  return !!length && baseIndexOf(array, value, 0) > -1;
}

function overArg(func, transform) {
  return function(arg) {
    return func(transform(arg));
  };
}

function baseToPairs(object, props) {
  return arrayMap(props, function(key) {
    return [key, object[key]];
  });
}

function baseValues(object, props) {
  return arrayMap(props, function(key) {
    return object[key];
  });
}

export default function slideReset(speed, runCallbacks = true, internal) {
  const swiper = this;
  if (swiper.destroyed) return;
  if (typeof speed === 'undefined') {
    speed = swiper.params.speed;
  }
  return swiper.slideTo(swiper.activeIndex, speed, runCallbacks, internal);
}

function getOrInsertComputed(map, key, callback) {
  if (!map.has(key)) {
    const value = callback(key);
    map.set(key, value);
  }

  return map.get(key);
}

removeDependency(dependency) {
	const idx = this.dependencies.indexOf(dependency);
	if (idx >= 0) {
		this.dependencies.splice(idx, 1);
	}
}

updateHash(hash, context) {
	for (const dep of this.dependencies) {
		dep.updateHash(hash, context);
	}
	for (const block of this.blocks) {
		block.updateHash(hash, context);
	}
}

serialize(obj, context) {
	context.write(obj.errors);
	context.write(obj.message);
	context.write(obj.stack);
	context.write(obj.cause);
}

export default function isAxiosError(payload) {
  return utils.isObject(payload) && payload.isAxiosError === true;
}

class ConfigError extends Error {
  name = "ConfigError";
}

class UndefinedParserError extends Error {
  name = "UndefinedParserError";
}

if (optionalChained) {
  const chainNode = this.startNodeAt(start)
  chainNode.expression = base
  base = this.finishNode(chainNode, "ChainExpression")
}

while (!this.closes(tt.braceR, indent, line)) {
  const element = this.parseClassElement()
  if (element) node.body.body.push(element)
}

if (this.options.preserveParens) {
  let par = this.startNodeAt(startPos, startLoc)
  par.expression = val
  return this.finishNode(par, "ParenthesizedExpression")
} else {
  return val
}

for (const name of state.backReferenceNames) {
  if (!state.groupNames[name]) {
    state.raise("Invalid named capture referenced")
  }
}

for (let i = this.labels.length - 1; i >= 0; i--) {
  let label = this.labels[i]
  if (label.statementStart === node.start) {
    // Update information about previous labels on this node
    label.statementStart = this.start
    label.kind = kind
  } else break
}

if (method.kind === "constructor") {
  if (isGenerator) this.raise(key.start, "Constructor can't be a generator")
  if (isAsync) this.raise(key.start, "Constructor can't be an async method")
} else if (method.static && checkKeyName(method, "prototype")) {
  this.raise(key.start, "Classes may not have a static property named prototype")
}

if (checkKeyName(field, "constructor")) {
  this.raise(field.key.start, "Classes can't have a field named 'constructor'")
} else if (field.static && checkKeyName(field, "prototype")) {
  this.raise(field.key.start, "Classes can't have a static field named 'prototype'")
}

try {
  abortEmitter.emit(
    'abort',
    !reason || reason.type ? new CanceledError(null, config, req) : reason
  );
} catch (err) {
  // ignore emit errors
}

if (config.cancelToken || config.signal) {
  config.cancelToken && config.cancelToken.subscribe(abort);
  if (config.signal) {
    config.signal.aborted ? abort() : config.signal.addEventListener('abort', abort);
  }
}

if (onDownloadProgress) {
  [downloadThrottled, flushDownload] = progressEventReducer(onDownloadProgress, true);
  request.addEventListener('progress', downloadThrottled);
}

if (onUploadProgress && request.upload) {
  [uploadThrottled, flushUpload] = progressEventReducer(onUploadProgress);

  request.upload.addEventListener('progress', uploadThrottled);

  request.upload.addEventListener('loadend', flushUpload);
}

export default function spread(callback) {
  return function wrap(arr) {
    return callback.apply(null, arr);
  };
}

switch (key.type) {
case "Identifier": name = key.name; break
case "Literal": name = String(key.value); break
default: return
}

if (isArray(options.onToken)) {
  let tokens = options.onToken
  options.onToken = (token) => tokens.push(token)
}
